"use strict";(globalThis.webpackChunkp4samd_handbook=globalThis.webpackChunkp4samd_handbook||[]).push([[849],{86164(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"3.0.x (Current)","banner":null,"badge":true,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"P4SaMD":[{"type":"link","href":"/docs/p4samd/overview","label":"What is P4SaMD?","docId":"p4samd/overview","unlisted":false},{"type":"link","href":"/docs/p4samd/faq","label":"FAQ","docId":"p4samd/faq","unlisted":false},{"label":"Installation","type":"category","items":[{"type":"link","href":"/docs/p4samd/installation/installation_overview","label":"Overview","docId":"p4samd/installation/installation_overview","unlisted":false},{"type":"link","href":"/docs/p4samd/installation/installation_saas","label":"SaaS","docId":"p4samd/installation/installation_saas","unlisted":false},{"type":"link","href":"/docs/p4samd/installation/installation_on_premise","label":"On-premise","docId":"p4samd/installation/installation_on_premise","unlisted":false}],"collapsed":true,"collapsible":true},{"label":"Handbook","type":"category","items":[{"type":"link","href":"/docs/p4samd/handbook/getting_started","label":"Getting Started","docId":"p4samd/handbook/getting_started","unlisted":false},{"type":"link","href":"/docs/p4samd/handbook/organizations","label":"Organizations","docId":"p4samd/handbook/organizations","unlisted":false},{"type":"link","href":"/docs/p4samd/handbook/products","label":"Products & Projects","docId":"p4samd/handbook/products","unlisted":false},{"type":"link","href":"/docs/p4samd/handbook/requirements","label":"Requirements","docId":"p4samd/handbook/requirements","unlisted":false},{"type":"link","href":"/docs/p4samd/handbook/version_management","label":"Version Management","docId":"p4samd/handbook/version_management","unlisted":false},{"label":"Brownfield Import","type":"category","items":[{"type":"link","href":"/docs/p4samd/handbook/brownfield/overview","label":"Overview","docId":"p4samd/handbook/brownfield/overview","unlisted":false},{"type":"link","href":"/docs/p4samd/handbook/brownfield/import-wizard","label":"Import Wizard","docId":"p4samd/handbook/brownfield/import-wizard","unlisted":false}],"collapsed":true,"collapsible":true}],"collapsed":true,"collapsible":true},{"label":"Tutorials","type":"category","items":[{"type":"link","href":"/docs/p4samd/tutorials/implementing-iec-62304","label":"IEC 62304 Compliance","docId":"p4samd/tutorials/implementing-iec-62304","unlisted":false},{"type":"link","href":"/docs/p4samd/tutorials/brownfield-analysis","label":"Brownfield Regulatory Analysis","docId":"p4samd/tutorials/brownfield-analysis","unlisted":false}],"collapsed":true,"collapsible":true},{"label":"Security","type":"category","items":[{"type":"link","href":"/docs/p4samd/security/roles_permissions","label":"Roles and Permissions","docId":"p4samd/security/roles_permissions","unlisted":false}],"collapsed":true,"collapsible":true},{"label":"Release Notes","type":"category","items":[{"type":"link","href":"/docs/p4samd/release-notes/v3.0","label":"Current (v3.x)","docId":"p4samd/release-notes/v3.0","unlisted":false},{"type":"link","href":"/docs/p4samd/release_notes","label":"Archived (v2.x)","docId":"p4samd/release_notes","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"p4samd/configuration":{"id":"p4samd/configuration","title":"Configuration","description":"After the installation of Mia-Care P4SaMD, the configuration activities are carried out by Mia-Care qualified personnel to adapt the system to the customer\u2019s specific requirements. This ensures seamless integration and functionality within the customer\u2019s environment."},"p4samd/faq":{"id":"p4samd/faq","title":"Frequently Asked Questions","description":"Find answers to the most common questions about P4SaMD. Use the search bar to filter by keyword, or browse by category.","sidebar":"P4SaMD"},"p4samd/handbook/brownfield/import-wizard":{"id":"p4samd/handbook/brownfield/import-wizard","title":"Brownfield Import Wizard","description":"This page walks you through each step of the Brownfield Import wizard. To launch it, click Brownfield in the left sidebar, then click + Create Project on the Sessions page.","sidebar":"P4SaMD"},"p4samd/handbook/brownfield/overview":{"id":"p4samd/handbook/brownfield/overview","title":"Brownfield Import \u2014 Overview","description":"The Brownfield Import feature allows you to onboard an existing software project \u2014 one already in development or even in production \u2014 into P4SaMD. The platform analyzes your current state against the applicable regulatory framework and produces a prioritized compliance gap analysis and a remediation plan you can act on immediately.","sidebar":"P4SaMD"},"p4samd/handbook/changes":{"id":"p4samd/handbook/changes","title":"Changes","description":"Overview"},"p4samd/handbook/document_engine":{"id":"p4samd/handbook/document_engine","title":"Documentation Engine","description":"Overview"},"p4samd/handbook/getting_started":{"id":"p4samd/handbook/getting_started","title":"Getting Started","description":"This guide walks you through your first session in P4SaMD \u2014 from logging in to navigating your first project.","sidebar":"P4SaMD"},"p4samd/handbook/insight_and_suggestions":{"id":"p4samd/handbook/insight_and_suggestions","title":"Insight & Suggestions","description":"P4SaMD ensures compliance with IEC 62304 rules by analyzing Software Items, Requirements, Risks, and Tests. It detects inconsistencies and suggests modifications to enhance compliance and reduce risks, streamlining medical software development. The user is guided by suggestions indicating necessary actions to achieve compliance, including mandatory, recommended, and optional improvements."},"p4samd/handbook/organizations":{"id":"p4samd/handbook/organizations","title":"Organizations & Multi-Tenancy","description":"P4SaMD is a multi-tenant platform. A single installation serves multiple independent organizations simultaneously, with complete data isolation between them \u2014 your projects, users, and data are never visible to anyone outside your organization.","sidebar":"P4SaMD"},"p4samd/handbook/products":{"id":"p4samd/handbook/products","title":"Products & Projects","description":"The Products page is the organization-level hub that lists all medical device software projects in your organization. Access it by clicking All Products in the sidebar (visible when no project is selected), or by navigating up to the organization level via the breadcrumb.","sidebar":"P4SaMD"},"p4samd/handbook/references":{"id":"p4samd/handbook/references","title":"References","description":"In this section you can add links to additional documentation or resources related to your SaMD projects, including regulations, guidelines and mockups, and such providing a quick access to the most relevant resources directly from Mia-Care P4SaMD to all your team members."},"p4samd/handbook/reports":{"id":"p4samd/handbook/reports","title":"Reports","description":"Mia-Care P4SaMD can automatically generate documentation based on information about managed entities, like risks, requirements, tests and changes, to ensure compliance with most common documentation requirements outlined in international regulation and standards related to SaMD development."},"p4samd/handbook/requirements":{"id":"p4samd/handbook/requirements","title":"Requirements Management","description":"The Requirements section of P4SaMD is where you capture, organize, trace, and verify the software requirements for your medical device project. Work-item management is built directly into the platform \u2014 no external ALM tool is needed. Open it by clicking Requirements in the left project sidebar.","sidebar":"P4SaMD"},"p4samd/handbook/risks":{"id":"p4samd/handbook/risks","title":"Risks","description":"Overview"},"p4samd/handbook/sbom":{"id":"p4samd/handbook/sbom","title":"Software Bill Of Materials (SBOM)","description":"When developing Software as a Medical Device (SaMD), the Software Bill of Materials (SBOM) is a crucial tool for enhancing transparency, security, and compliance. A SBOM is an inventory of all the software components, libraries, and dependencies that make up a particular software item and includes information like versioning, licensing and known vulnerabilities. Much like a bill of materials in hardware manufacturing, it provides a detailed mapping of what constitutes the software."},"p4samd/handbook/software_items":{"id":"p4samd/handbook/software_items","title":"Software Items","description":"The section allows users to view, create, and edit software items in the Software System Version. It provides an intuitive interface for managing software items, including detailed views, adding new entries, and updating existing records. Additionally, using the console, software items are also detected automatically, ensuring efficient and seamless handling of software-related data."},"p4samd/handbook/software_verification":{"id":"p4samd/handbook/software_verification","title":"Software Verification","description":"Ensuring the reliability and safety of Software as a Medical Device (SaMD) requires a balanced approach between automated and manual testing. Automated testing is crucial for early and efficient assessment of software quality, allowing fast execution of unit, integration, and system tests and ensuring regulatory compliance, such as adherence to IEC 62304, thanks to consistent and continuous validation during the entire software lifecycle."},"p4samd/handbook/system_overview":{"id":"p4samd/handbook/system_overview","title":"System Overview","description":"Introduction"},"p4samd/handbook/system_versions":{"id":"p4samd/handbook/system_versions","title":"System Versions","description":"Overview"},"p4samd/handbook/version_management":{"id":"p4samd/handbook/version_management","title":"Version Management","description":"P4SaMD uses workspace versions to track the evolution of your medical device software through its development lifecycle. Each version is a named, timestamped snapshot of all project artifacts \u2014 requirements, risks, software items, and test evidence \u2014 at a specific point in time, aligned with IEC 62304 configuration management requirements.","sidebar":"P4SaMD"},"p4samd/handbook/vulnerabilities":{"id":"p4samd/handbook/vulnerabilities","title":"Vulnerabilities","description":"Vulnerabilities Overview"},"p4samd/installation/installation_on_premise":{"id":"p4samd/installation/installation_on_premise","title":"On-premise Installation","description":"On-premise deployments run P4SaMD entirely within infrastructure you own and manage. The platform is delivered as a set of Kubernetes workloads and is distributed as OCI container images. On-premise installations include the full Enterprise feature set.","sidebar":"P4SaMD"},"p4samd/installation/installation_overview":{"id":"p4samd/installation/installation_overview","title":"Deployment Modes","description":"P4SaMD is available in three deployment modes. Each mode is designed for a different organizational profile \u2014 from teams that want to be up and running in minutes to enterprises that require full infrastructure ownership.","sidebar":"P4SaMD"},"p4samd/installation/installation_saas":{"id":"p4samd/installation/installation_saas","title":"SaaS Deployment","description":"P4SaMD offers two cloud-hosted deployment options: Multi-tenant SaaS and Dedicated SaaS. Both are fully managed by Mia-Care \u2014 you never need to provision servers, manage databases, or handle platform upgrades.","sidebar":"P4SaMD"},"p4samd/monitoring":{"id":"p4samd/monitoring","title":"Monitoring","description":"Mia-Care P4SaMD is installed by the Mia-Care team, ensuring the right configuration and installation procedure. After installation, the Mia-Care team also sets up the necessary dashboards for monitoring. These dashboards can be modified based on customer needs."},"p4samd/overview":{"id":"p4samd/overview","title":"What is P4SaMD?","description":"P4SaMD (Platform for Software as a Medical Device) is the compliance governance platform built by Mia-Care to help development teams design, build, and certify medical device software efficiently. Version 3 is a complete re-architecture of the platform: it runs as a standalone product with its own dedicated interface, independent of any other software infrastructure.","sidebar":"P4SaMD"},"p4samd/release_notes":{"id":"p4samd/release_notes","title":"Archived Release Notes (v2.x)","description":"This page archives the release notes for P4SaMD version 2.x. For the current v3.x release notes, see Current (v3.x).","sidebar":"P4SaMD"},"p4samd/release-notes/v2.0":{"id":"p4samd/release-notes/v2.0","title":"Version 2.0 Release Notes","description":"February 26th, 2025"},"p4samd/release-notes/v2.1":{"id":"p4samd/release-notes/v2.1","title":"Version 2.1 Release Notes","description":"May 28th, 2025"},"p4samd/release-notes/v2.2":{"id":"p4samd/release-notes/v2.2","title":"Version 2.2 Release Notes","description":"July 18th, 2025"},"p4samd/release-notes/v2.3":{"id":"p4samd/release-notes/v2.3","title":"Version 2.3 Release Notes","description":"November 26th, 2025"},"p4samd/release-notes/v2.3.1":{"id":"p4samd/release-notes/v2.3.1","title":"Version 2.3.1 Release Notes","description":"December 30th, 2025"},"p4samd/release-notes/v2.4":{"id":"p4samd/release-notes/v2.4","title":"Version 2.4 Release Notes","description":"February 10th, 2026"},"p4samd/release-notes/v2.5":{"id":"p4samd/release-notes/v2.5","title":"Version 2.5 Release Notes","description":"March 18th, 2026"},"p4samd/release-notes/v3.0":{"id":"p4samd/release-notes/v3.0","title":"Release Notes \u2014 Current (v3.x)","description":"P4SaMD v3.0","sidebar":"P4SaMD"},"p4samd/security/roles_permissions":{"id":"p4samd/security/roles_permissions","title":"Roles and Permissions","description":"P4SaMD v3 has its own role-based access control (RBAC) system, independent of any external platform. Roles are assigned at two levels: Organization and Project.","sidebar":"P4SaMD"},"p4samd/system_requirement":{"id":"p4samd/system_requirement","title":"System Requirements","description":"Mia-Care P4SaMD is validated to develop SaMD, if you need additional documentation or information please contact us or check the FAQ section."},"p4samd/tutorials/brownfield-analysis":{"id":"p4samd/tutorials/brownfield-analysis","title":"Tutorial: Analyzing a Legacy Project for Regulatory Compliance","description":"This tutorial demonstrates how to use P4SaMD\'s Brownfield Import feature to analyze an existing software product that was developed without formal IEC 62304 compliance \u2014 identifying gaps, assessing regulatory risk, and creating a prioritized remediation roadmap.","sidebar":"P4SaMD"},"p4samd/tutorials/implementing-iec-62304":{"id":"p4samd/tutorials/implementing-iec-62304","title":"Tutorial: Implementing a Medical Device with IEC 62304","description":"This tutorial walks through the complete lifecycle of developing a medical device software product in P4SaMD following IEC 62304 requirements \u2014 from initial product setup through version release and documentation generation.","sidebar":"P4SaMD"}}}}')}}]);